import './index.css';

import {
  useEffect,
  useState
} from 'react';

import Header
from '../../components/common/Header';

import {
  getStudentMarks
} from '../../services/studentMarksService';

function StudentMarks() {

  const [marks, setMarks] =
    useState([]);

  const [loading, setLoading] =
    useState(true);

  const [totalMarks, setTotalMarks] =
    useState(0);

  useEffect(() => {

    loadMarks();

  }, []);

  // LOAD MARKS
  const loadMarks =
    async () => {

    try {

      const data =
        await getStudentMarks();

      console.log(data);

      setMarks(data);

      // TOTAL MARKS
      let total = 0;

      data.forEach((item) => {

        total +=
          Number(
            item.marks_obtained
          );

      });

      setTotalMarks(total);

    } catch (error) {

      console.log(error);

    } finally {

      setLoading(false);

    }

  };

  return (

    <div className="student-marks-page">

      {/* HEADER */}

      <Header />


      {/* CONTENT */}

      <div className="student-marks-content">

        <div className="marks-header">

          <h1>
            My Marks
          </h1>

          <div className="total-card">

            <h2>
              Total Marks
            </h2>

            <p>
              {totalMarks}
            </p>

          </div>

        </div>


        {

          loading
          ? (

            <div className="loading-box">

              Loading...

            </div>

          )
          : (

            <div className="marks-grid">

              {

                marks.length > 0
                ? (

                  marks.map((mark) => (

                    <div
                      key={mark.id}
                      className="mark-card"
                    >

                      <div className="card-top">

                        <h3>
                          {mark.subject_name}
                        </h3>

                        <span className="grade-badge">

                          {mark.grade}

                        </span>

                      </div>


                      <div className="mark-info">

                        <p>

                          <strong>
                            Subject ID:
                          </strong>

                          {' '}

                          {mark.subject_id}

                        </p>

                        <p>

                          <strong>
                            Assessment ID:
                          </strong>

                          {' '}

                          {mark.assessment_id}

                        </p>

                        <p>

                          <strong>
                            Marks:
                          </strong>

                          {' '}

                          {mark.marks_obtained}

                        </p>

                        <p>

                          <strong>
                            Percentage:
                          </strong>

                          {' '}

                          {mark.percentage}%

                        </p>

                      </div>

                    </div>

                  ))

                )
                : (

                  <div className="empty-box">

                    No Marks Available

                  </div>

                )

              }

            </div>

          )

        }

      </div>

    </div>

  );

}

export default StudentMarks;
